using System.ComponentModel.DataAnnotations;

namespace sv_7e86e84611d24c68b596de5e400dd714.Models;

public enum SessionPreference
{
    Morning,
    Afternoon,
    Evening
}

public class RegistrationModel
{
    [Required(ErrorMessage = "Name is required.")]
    [Display(Name = "Attendee Name")]
    public string Name { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Please enter a valid email address.")]
    public string Email { get; set; } = string.Empty;

    [Range(0, 5, ErrorMessage = "Number of guests must be between 0 and 5.")]
    [Display(Name = "Number of Guests")]
    public int NumberOfGuests { get; set; }

    [Display(Name = "Preferred Session")]
    public SessionPreference PreferredSession { get; set; } = SessionPreference.Morning;

    [Display(Name = "Special Dietary Requirements")]
    public string? DietaryRequirements { get; set; }
}

namespace sv_7e86e84611d24c68b596de5e400dd714.Services;

public class RegistrationService
{
    /// <summary>
    /// Validates a registration request and returns field-specific errors.
    /// Returns an empty dictionary when validation passes.
    /// </summary>
    public Task<Dictionary<string, string>> ValidateAsync(string email)
    {
        var errors = new Dictionary<string, string>();

        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(Models.RegistrationModel.Email)] = "This email is already registered.";
        }

        return Task.FromResult(errors);
    }
}

@page "/register"
@rendermode InteractiveServer
@using sv_7e86e84611d24c68b596de5e400dd714.Models
@using sv_7e86e84611d24c68b596de5e400dd714.Services
@inject RegistrationService RegistrationService

<PageTitle>Event Registration</PageTitle>

<h3>Event Registration</h3>

@if (submitted)
{
    <div class="alert alert-success mt-3">
        <strong>Registration successful!</strong> Thank you, @Model.Name.
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="register" class="mt-3" style="max-width: 500px;">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="name" class="form-label">Attendee Name</label>
            <InputText id="name" class="form-control" @bind-Value="Model.Name" />
            <ValidationMessage For="() => Model.Name" />
        </div>

        <div class="mb-3">
            <label for="email" class="form-label">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
            @if (!string.IsNullOrEmpty(serverEmailError))
            {
                <div class="validation-message">@serverEmailError</div>
            }
        </div>

        <div class="mb-3">
            <label for="guests" class="form-label">Number of Guests</label>
            <InputNumber id="guests" class="form-control" @bind-Value="Model.NumberOfGuests" />
            <ValidationMessage For="() => Model.NumberOfGuests" />
        </div>

        <div class="mb-3">
            <label for="session" class="form-label">Preferred Session</label>
            <InputSelect id="session" class="form-select" @bind-Value="Model.PreferredSession">
                @foreach (var session in Enum.GetValues<SessionPreference>())
                {
                    <option value="@session">@session</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.PreferredSession" />
        </div>

        <div class="mb-3">
            <label for="dietary" class="form-label">Special Dietary Requirements</label>
            <InputTextArea id="dietary" class="form-control" @bind-Value="Model.DietaryRequirements" />
        </div>

        <button type="submit" class="btn btn-primary" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
            }
            Register
        </button>
    </EditForm>
}

@code {
    private RegistrationModel Model { get; set; } = new();
    private string? serverEmailError;
    private bool submitted;
    private bool isSubmitting;

    private async Task HandleSubmit()
    {
        serverEmailError = null;
        isSubmitting = true;

        try
        {
            var errors = await RegistrationService.ValidateAsync(Model.Email);

            if (errors.TryGetValue(nameof(Model.Email), out var emailError))
            {
                serverEmailError = emailError;
                return;
            }

            submitted = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

